module SR_latch (
    input wire Inv_S,
    input wire R,
    output reg Q,
    output reg Q_bar
);
    always @(Inv_S, R) begin
        if (Inv_S && !R) begin
            Q <= 1;
            Q_bar <= 0;
        end else if (!Inv_S && R) begin
            Q <= 0;
            Q_bar <= 1;
        end
        // Maintain state when both Inv_S and R are low
    end
endmodule
